// Prepare search queries for The Org and LinkedIn to find decision makers
const items = $input.all();
const results = [];

for (const item of items) {
  const company = item.json;
  const companyName = company.company_name;
  const targetRoles = company.target_roles || [
    'Procurement Head', 'Coffee Buyer', 'Category Manager',
    'Head of Purchasing', 'Supply Chain Director', 'Sourcing Manager',
    'CEO', 'Managing Director', 'Founder', 'COO'
  ];

  // The Org search
  results.push({
    company_name: companyName,
    company_data: company,
    search_type: 'theorg',
    search_url: `https://theorg.com/api/v1/organizations/search?q=${encodeURIComponent(companyName)}`,
    target_roles: targetRoles
  });

  // LinkedIn search queries for each role type
  const roleGroups = [
    ['Procurement', 'Purchasing', 'Sourcing', 'Buyer'],
    ['Category Manager', 'Supply Chain', 'Operations'],
    ['CEO', 'Founder', 'Managing Director', 'COO', 'Owner']
  ];

  for (const roleGroup of roleGroups) {
    const roleQuery = roleGroup.join(' OR ');
    results.push({
      company_name: companyName,
      company_data: company,
      search_type: 'linkedin_search',
      search_query: `site:linkedin.com/in/ "${companyName}" (${roleQuery})`,
      role_group: roleGroup[0],
      target_roles: targetRoles
    });
  }
}

return results.map(r => ({ json: r }));

// Extract contacts from The Org results
const items = $input.all();
const contacts = [];

for (const item of items) {
  const data = item.json;
  const orgResults = data.organizations || data.results || data.data || [];
  const companyName = data.company_name || $('Webhook - New Company').first().json.company_name;

  if (Array.isArray(orgResults)) {
    for (const org of orgResults) {
      const members = org.members || org.people || org.team || [];
      for (const member of members) {
        contacts.push({
          full_name: member.name || `${member.first_name || ''} ${member.last_name || ''}`.trim(),
          job_title: member.title || member.position || member.role || '',
          company_name: companyName,
          linkedin_url: member.linkedin_url || member.linkedin || '',
          source: 'theorg',
          found_at: new Date().toISOString()
        });
      }
    }
  }
}

return contacts.length > 0 ? contacts.map(c => ({ json: c })) : [{ json: { no_results: true } }];

// Extract contacts from LinkedIn search results
const items = $input.all();
const contacts = [];

for (const item of items) {
  const webResults = item.json?.web?.results || [];
  const companyName = item.json?.company_name || '';

  for (const r of webResults) {
    const url = r.url || '';
    const title = r.title || '';
    const description = r.description || '';

    if (!url.includes('linkedin.com/in/')) continue;

    // Extract name from LinkedIn title (usually "Name - Title - Company")
    const nameParts = title.split(/\s*[-|]\s*/);
    const fullName = nameParts[0]?.trim() || '';
    const jobTitle = nameParts[1]?.trim() || '';

    if (!fullName || fullName.length < 3) continue;

    contacts.push({
      full_name: fullName,
      job_title: jobTitle,
      company_name: companyName,
      linkedin_url: url,
      description: description.substring(0, 200),
      source: 'linkedin_search',
      found_at: new Date().toISOString()
    });
  }
}

return contacts.length > 0 ? contacts.map(c => ({ json: c })) : [{ json: { no_results: true } }];

// Deduplicate and rank contacts, pick top 3 per company
const items = $input.all().filter(i => !i.json.no_results);
const byCompany = new Map();

const rolePriority = {
  'procurement': 10, 'purchasing': 10, 'buyer': 9, 'sourcing': 9,
  'category manager': 8, 'supply chain': 7, 'operations': 6,
  'ceo': 5, 'founder': 5, 'managing director': 5, 'coo': 4,
  'director': 3, 'manager': 2, 'head': 8
};

const scoreRole = (title) => {
  if (!title) return 0;
  const lower = title.toLowerCase();
  let maxScore = 0;
  for (const [keyword, score] of Object.entries(rolePriority)) {
    if (lower.includes(keyword)) maxScore = Math.max(maxScore, score);
  }
  return maxScore;
};

for (const item of items) {
  const contact = item.json;
  const company = contact.company_name?.toLowerCase() || 'unknown';

  if (!byCompany.has(company)) byCompany.set(company, []);

  // Dedupe by name
  const existing = byCompany.get(company);
  const nameKey = contact.full_name?.toLowerCase().replace(/[^a-z]/g, '');
  if (existing.some(c => c.full_name?.toLowerCase().replace(/[^a-z]/g, '') === nameKey)) continue;

  contact.role_score = scoreRole(contact.job_title);
  existing.push(contact);
}

const finalContacts = [];
for (const [company, contacts] of byCompany) {
  // Sort by role relevance, take top 3
  const sorted = contacts.sort((a, b) => b.role_score - a.role_score);
  const top3 = sorted.slice(0, 3);

  top3.forEach((contact, index) => {
    finalContacts.push({
      ...contact,
      contact_rank: index + 1, // 1 = primary, 2 = secondary, 3 = tertiary
      pipeline_stage: 'contact_found'
    });
  });
}

return finalContacts.map(c => ({ json: c }));
